Wikipedia Seitenlänge extrahieren

# Hilfsfunktion, um die Seitengröße zu extrahieren
get_wiki_size &lt;- function(title) {
  # Wir fragen die Info für die deutsche Wikipedia ab
  info &lt;- page_info("de", "wikipedia", page = title, clean_response = TRUE)

  # Extrahiere die Länge in Bytes (standardmäßig im Feld 'length' enthalten)
  if (!is.null(info[[1]]$length)) {
    return(info[[1]]$length)
  } else {
    return(NA)
  }
}

# Anwendung auf die Liste von Titeln
df &lt;- df %&gt;%
  mutate(article_length = map_dbl(titles, get_wiki_size))

Wikipedia Backlinks extrahieren

get_backlinks &lt;- function(title) {
  backl &lt;- page_backlinks("de", "wikipedia", page = title, limit = 500)

  # Extract backlink count
  if (!is.null(backl$query$backlinks)) {
    return(length(backl$query$backlinks))
  } else {
    warning("No backlinks found or page does not exist.")
    return(0)
  }
}
# Anwendung auf die Liste von Titeln
df &lt;- df %&gt;%
  mutate(article_backl = map_dbl(titles, get_backlinks))

Wikipedia Pageviews extrahieren

get_wiki_views_direct &lt;- function(title) {
  # Wir müssen Leerzeichen in Titeln für die URL mit %20 kodieren
  safe_title &lt;- URLencode(title, reserved = TRUE)

  # Die URL der Wikimedia API für Pageviews (kumuliert für 2025)
  # Struktur: project/access/agent/article/granularity/start/end
  url &lt;- paste0(
    "https://wikimedia.org/api/rest_v1/metrics/pageviews/per-article/de.wikipedia/all-access/user/",
    safe_title,
    "/monthly/2025042700/2026042700"
  )

  res &lt;- GET(url, add_headers(`User-Agent` = "Daria Tisch, TH Nuernberg"))

  if (status_code(res) == 200) {
    data &lt;- fromJSON(content(res, as = "text", encoding = "UTF-8"))
    return(sum(data$items$views))
  } else {
    return(NA) # Falls die API die Seite nicht findet
  }
}

# Anwendung auf deine Titel
df &lt;- df %&gt;%
  mutate(total_views = map_dbl(titles, function(x) {
    Sys.sleep(0.001) # Kurze Pause zur Schonung der API
    get_wiki_views_direct(x)
  }))
